typedef struct {
    char* data;
    size_t size;
    size_t capacity;
    uint8_t guard_page[GUARD_PAGE_SIZE];  // Guard page
} SafeBuffer;

SafeBuffer* safe_buffer_create(size_t initial_size) {
    if (initial_size > BUFFER_SIZE_MAX) return NULL;
    SafeBuffer* buf = malloc(sizeof(SafeBuffer));
    buf->data = malloc(initial_size);
    buf->capacity = initial_size;
    buf->size = 0;
    memset(buf->guard_page, 0xDEADBEEF, GUARD_PAGE_SIZE);
    return buf;
}

int safe_buffer_write(SafeBuffer* buf, const char* data, size_t len) {
    if (!buf || !data) return -1;
    if (buf->size + len > buf->capacity) return -1;  // Boundary check
    if (*(uint32_t*)buf->guard_page != 0xDEADBEEF) return -2;  // Guard check
    memcpy(buf->data + buf->size, data, len);
    buf->size += len;
    return 0;
}

void safe_buffer_free(SafeBuffer* buf) {
    if (!buf) return;
    memset(buf->data, 0, buf->capacity);  // Clear before free
    free(buf->data);
    memset(buf->guard_page, 0, GUARD_PAGE_SIZE);
