// 메모리 누수 방어 - Reference Counting + Auto GC
typedef struct {
    void* data;
    int ref_count;
    void (*destructor)(void*);
} ManagedObject;

ManagedObject* managed_create(void* data, void (*destructor)(void*)) {
    ManagedObject* obj = malloc(sizeof(ManagedObject));
    obj->data = data;
    obj->ref_count = 1;
    obj->destructor = destructor;
    return obj;
}

ManagedObject* managed_retain(ManagedObject* obj) {
    if (!obj) return NULL;
    obj->ref_count++;
    return obj;
}

int managed_release(ManagedObject* obj) {
    if (!obj) return -1;
    obj->ref_count--;

    if (obj->ref_count <= 0) {
        if (obj->destructor && obj->data) {
            obj->destructor(obj->data);
        }
        free(obj);
        return 1;  // Object freed
    }
    return 0;  // Object still alive
}

// 자동 cleanup 스코프
#define AUTO_RELEASE __attribute__((cleanup(auto_release_cleanup)))

void auto_release_cleanup(ManagedObject** obj) {
    if (obj && *obj) {
        managed_release(*obj);
    }
}

