            c11_total += result["vulnerabilities_found"]
            c11_fixed += len(result["fixes_applied"])
            status_emoji = "✅" if result["status"] == "REMEDIATED" else "⚠️"
            report.append(f"  {status_emoji} {proj_name}: {result['improvement_percentage']:.0f}% 개선")

        report.append("")
        report.append(f"  C11 소계: {c11_fixed}/{c11_total} 취약점 수정 ({(c11_fixed/max(c11_total,1))*100:.1f}%)")
        report.append("")

        # FreeLang 프로젝트 결과
        report.append("【FreeLang 프로젝트 (9개) 수정 결과】")
        fl_fixed = 0
        fl_total = 0
        for proj_name, result in self.results.items():
            if proj_name not in PROJECTS["freelang_projects"]:
                continue
            fl_total += result["vulnerabilities_found"]
            fl_fixed += len(result["fixes_applied"])
            status_emoji = "✅" if result["status"] == "REMEDIATED" else "⚠️"
