        report.append("【취약점 타입별 수정 현황】")
        vuln_stats = {}
        for result in self.results.values():
            for fix in result["fixes_applied"]:
                vuln_type = fix["type"]
                if vuln_type not in vuln_stats:
                    vuln_stats[vuln_type] = {"count": 0, "severity": fix["severity"]}
