        report.append("【프로덕션 배포 준비도】")
        ready_count = sum(1 for r in self.results.values() if r["status"] == "REMEDIATED")
        report.append(f"  배포 준비 완료: {ready_count}/{len(self.results)} 프로젝트 ({(ready_count/len(self.results))*100:.1f}%)")
        report.append(f"  권장사항: {'프로덕션 배포 가능' if ready_count > len(self.results) * 0.95 else '추가 검토 필요'}")
        report.append("")

        # 권장 사항
        report.append("【권장 사항】")
